import{_ as t,o as e,c as r,a2 as o}from"./chunks/framework.DnrXFDHb.js";const p=JSON.parse('{"title":"F07: 存貨週轉效率同業對比 - 財務審計專家 審計報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/3163_波若威/20260502/F07_存貨週轉效率同業對比.md","filePath":"審計報告庫/財務審計/3163_波若威/20260502/F07_存貨週轉效率同業對比.md"}'),i={name:"審計報告庫/財務審計/3163_波若威/20260502/F07_存貨週轉效率同業對比.md"};function l(n,a,s,h,d,_){return e(),r("div",null,[...a[0]||(a[0]=[o('<p>我已讀取 03_審計專家_任務執行與技術協議.md，我將以專業職人視角，榨取最高密度的財務洞見。</p><h1 id="f07-存貨週轉效率同業對比-財務審計專家-審計報告" tabindex="-1">F07: 存貨週轉效率同業對比 - 財務審計專家 審計報告 <a class="header-anchor" href="#f07-存貨週轉效率同業對比-財務審計專家-審計報告" aria-label="Permalink to &quot;F07: 存貨週轉效率同業對比 - 財務審計專家 審計報告&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><p>存貨週轉天數與同業相比是否具備競爭優勢？整體營運週期 (Cash Cycle) 是否處於擴張狀態？</p><h2 id="🎯-專家直斷-59-字" tabindex="-1">🎯 專家直斷（59 字） <a class="header-anchor" href="#🎯-專家直斷-59-字" aria-label="Permalink to &quot;🎯 專家直斷（59 字）&quot;">​</a></h2><ul><li><strong>核心結論</strong>：波若威 DIO 287 天居同業中段，優於上詮（436 天）與前鼎（679 天），但劣於聯鈞（236 天）；現金循環 50 天在同業中仍屬高效，惟從 2023 年 -110 天的極佳水準急遽惡化。</li><li><strong>風險評級</strong>：中</li><li><strong>數據時效</strong>：根據截至 2025 年最新公開數據</li></ul><h2 id="📊-診斷評級-147-字" tabindex="-1">📊 診斷評級（147 字） <a class="header-anchor" href="#📊-診斷評級-147-字" aria-label="Permalink to &quot;📊 診斷評級（147 字）&quot;">​</a></h2><p>2025 年同業 DIO：聯鈞236天→波若威287天→華星光172天→上詮436天→前鼎679天，波若威居中。關鍵警訊在趨勢：2023年DIO 155天（同業最佳）急遽跳升至2025年287天（+85%）。對比華星光從510天壓縮至172天（效率提升），聯鈞維持236天穩定。波若威DIO惡化幅度最大，存貨管理動能失速。現金循環50天仍優於同業，但靠DPO 318天支撐而非法存貨效率。</p><h2 id="🔍-答詢詳解-399-字" tabindex="-1">🔍 答詢詳解（399 字） <a class="header-anchor" href="#🔍-答詢詳解-399-字" aria-label="Permalink to &quot;🔍 答詢詳解（399 字）&quot;">​</a></h2><h3 id="一、週轉階差分析-波若威從同業領先者滑落至後段班" tabindex="-1">一、週轉階差分析：波若威從同業領先者滑落至後段班 <a class="header-anchor" href="#一、週轉階差分析-波若威從同業領先者滑落至後段班" aria-label="Permalink to &quot;一、週轉階差分析：波若威從同業領先者滑落至後段班&quot;">​</a></h3><p>2023 年波若威 DIO 155 天為同業最佳（優於聯鈞 114 天、華星光 254 天），展現極高效率的存貨管理。但 2024 年起情勢逆轉：DIO 跳升至 272 天，2025 年續升至 287 天，反觀華星光從 254 天進一步壓縮至 172 天（-32%），聯鈞維持 149-236 天。從「領先者」變為「追趕者」，波若威在存貨管理上的相對競爭優勢已經消失。更值得注意的是，波若威 DIO 在 2024 年（營收衰退期）率先惡化——存貨週轉放緩並非 2025 年營收復甦後的產物，而是在營收低谷期就已出現。</p><h3 id="二、現金循環的高品質來自超長-dpo-而非存貨效率" tabindex="-1">二、現金循環的高品質來自超長 DPO 而非存貨效率 <a class="header-anchor" href="#二、現金循環的高品質來自超長-dpo-而非存貨效率" aria-label="Permalink to &quot;二、現金循環的高品質來自超長 DPO 而非存貨效率&quot;">​</a></h3><p>波若威現金循環 50 天在同業中仍屬優良，但結構值得警惕：DSO 81 天（可控）、DIO 287 天（偏高）、DPO 318 天（極長）。換言之，高現金循環品質完全建立在超長應付帳款天數之上——即用供應商資金來補貼庫存持有。若 DPO 無法維持（供應商要求縮短付款週期），現金循環將迅速惡化至 100 天以上。</p><h3 id="三、同業不同調-華星光與聯鈞的存貨管理可做借鏡" tabindex="-1">三、同業不同調：華星光與聯鈞的存貨管理可做借鏡 <a class="header-anchor" href="#三、同業不同調-華星光與聯鈞的存貨管理可做借鏡" aria-label="Permalink to &quot;三、同業不同調：華星光與聯鈞的存貨管理可做借鏡&quot;">​</a></h3><p>華星光 DIO 從 510 天→172 天（四年壓縮 66%），其結構性轉變來自產品組合從電信低毛利大量庫存型轉向數據中心高週轉型。聯鈞 DIO 2025 年雖升至 236 天，但絕對水準仍優於波若威 51 天。兩者皆以更快的新產品導入節奏實現較優的存貨管理。</p><h2 id="💡-專家評析-270-字" tabindex="-1">💡 專家評析（270 字） <a class="header-anchor" href="#💡-專家評析-270-字" aria-label="Permalink to &quot;💡 專家評析（270 字）&quot;">​</a></h2><ol><li><p><strong>存貨管理效率退化的結構性風險</strong>：波若威 DIO 從 155 天翻倍至 287 天，且惡化早於同業（2024 年而非 2025 年）。這暗示公司早在 AI 產品放量前就已面臨傳統 WDM 產品存貨去化不順的問題。年報附註亦提及「科技快速變遷、市場競爭激烈」的存貨跌價風險。若 DIO 持續攀升，存貨跌價損失將從 2025 年的 380 萬大幅跳升。</p></li><li><p><strong>同業存貨競爭力正在流失</strong>：華星光與聯鈞在同樣的景氣下行週期中展現了更佳的存貨管理韌性。波若威在此階段的 DIO 相對弱勢意味著在爭取 AI 數據中心訂單時，可能面臨更嚴格的客戶庫存管理要求，需承擔更高的備貨風險與更短的出貨週期。</p></li><li><p><strong>DPO 彈性接近極限</strong>：DPO 318 天已處於同業極端水準（對比聯鈞 DPO 約 200 天）。繼續壓縮供應商付款週期的空間已相當有限。若供應鏈議價力轉弱，現金循環將面臨顯著壓力。</p></li></ol><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li><strong>計算工具</strong>：財務分析工具.py (inventory_check 3163 3450 4979 3363 4908 2022 2025)</li><li><strong>原始數據</strong>：FinMind TaiwanStockBalanceSheet, TaiwanStockFinancialStatements</li><li><strong>查詢參數</strong>：stock_id=3163,3450,4979,3363,4908; start=2022-01-01; end=2025-12-31</li><li><strong>關鍵核對碼</strong>：DIO(天) 2025: 波若威287 / 聯鈞236 / 華星光172 / 上詮436 / 前鼎679；現金循環(天) 2025: 波若威50 / 聯鈞71 / 上詮286</li></ul>',19)])])}const u=t(i,[["render",l]]);export{p as __pageData,u as default};
